SELECT "Febos Srl - Tommy Hilfiger Shoes IT, it shoes, FEBOS" AS [Codice Fornitore], "" AS Marca, Trademark.Description AS [Nuova Marca], Item.[Model Item No_] AS [Codice Riferimento Modello], Item.[Product Sex] AS Genere, Item_1.[Description 2], [Variable Code.Description] & "_" & [Variable Code.Variable Code] AS [Colore Fornitore], "" AS [Colore Amazon], [Sales Line].[Variable Code 02] AS Taglia, "" AS [UK Size Chart], "" AS [Taglia UK], "" AS [Taglia US], IIf(Left$([Item.Season Code],1)="I" Or Left$([Item.Season Code],1)="A","Autunno/Inverno","Primavera/Estate") AS Stagione, 20 & Mid$([Item.Season Code],2,2) AS Anno, "EAN" AS [Tipo Codice (EAN/UPC)], [NavisionEan-step0].[Cross-Reference No_] AS [EAN/UPC Code], Item.[Country_Region of Origin Code] AS [Paese D'origine], 0 AS [Quantita per pacco], Format$(Int(Val([sales line.unit price])),"0") & "." & Format$((Val([sales line.unit price])-Int(Val([sales line.unit price])))*100,"00") AS [Prezzo di Trasferimento], Format$(Int(Val([AmazonEstrazione_PrezzoAlPubblico.unit price])),"0") & "." & Format$((Val([AmazonEstrazione_PrezzoAlPubblico.unit price])-Int(Val([AmazonEstrazione_PrezzoAlPubblico.unit price])))*100,"00") AS [Prezzo Al Pubblico], Val([sales line.quantity]) AS [Quantita prima consegna]
FROM ((((((Item INNER JOIN [Sales Line] ON Item.No_ = [Sales Line].No_) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN Trademark ON Item_1.[Trademark Code] = Trademark.[Code]) INNER JOIN [Variable Code] ON (Item.[Variable Group 01] = [Variable Code].[Variable Group]) AND (Item.[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN [NavisionEan-step0] ON [Sales Line].No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN AmazonEstrazione_PrezzoAlPubblico ON [Sales Line].No_ = AmazonEstrazione_PrezzoAlPubblico.[Item No_]
WHERE ((([Sales Line].[Document No_])=[forms]![principale]![filtroodvean]) AND (([Sales Line].[Delete Reason])='') AND ((Item.[Advertising Material])=0));

